// Data Transfer Object (DTO) for the incoming webhook payload
class WebhookPayload {
    private String url;

    public String getUrl() {
        return url;
    }

    public void setUrl(String url) {
        this.url = url;
    }
}

// Service class to encapsulate the URL fetching logic
@Service
class ContentFetcherService {

    private final RestTemplate restTemplate;

    public ContentFetcherService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    public String fetchContent(String url) {
        // Basic URL validation
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be empty.");
        }
        if (!url.startsWith("http://") && !url.startsWith("https://")) {
            throw new IllegalArgumentException("Invalid URL protocol. Must be http:// or https://");
        }

        try {
            // Fetch content from the provided URL as a String
            return restTemplate.getForObject(url, String.class);
        } catch (HttpClientErrorException e) {
            // Handle client-side errors (4xx) from the target URL
            throw new RuntimeException("Client error (" + e.getStatusCode() + ") fetching URL: " + e.getResponseBodyAsString(), e);
        } catch (HttpServerErrorException e) {
            // Handle server-side errors (5xx) from the target URL
            throw new RuntimeException("Server error (" + e.getStatusCode() + ") fetching URL: " + e.getResponseBodyAsString(), e);
        } catch (ResourceAccessException e) {
            // Handle network errors, connection refused, unknown host, etc.
            throw new RuntimeException("Network or resource access error fetching URL: " + e.getMessage(), e);
        } catch (Exception e) {
            // Catch any other unexpected exceptions during the fetch
            throw new RuntimeException("An unexpected error occurred while fetching URL: " + e.getMessage(), e);
        }
    }
}

// REST Controller to handle incoming webhook requests
@RestController
@RequestMapping("/webhook")
class WebhookController {

    private final ContentFetcherService contentFetcherService;

    public WebhookController(ContentFetcherService contentFetcherService) {
        this.contentFetcherService = contentFetcherService;
    }

    @PostMapping("/fetch-content")
    public ResponseEntity<String> handleWebhook(@RequestBody WebhookPayload payload) {
        // Validate the incoming payload
        if (payload == null || payload.getUrl() == null || payload.getUrl().isEmpty()) {
            return ResponseEntity.badRequest().body("URL not provided in the webhook payload. Please include a 'url' field.");
        }

        try {
            // Fetch content using the service
            String content = contentFetcherService.fetchContent(payload.getUrl());
            // Return the fetched content with a 200 OK status
            return ResponseEntity.ok(content);
        } catch (IllegalArgumentException e) {
            // Handle validation errors from the ContentFetcherService
            return ResponseEntity.badRequest().body("Invalid URL provided: " + e.getMessage());
        } catch (RuntimeException e) {
            // Handle fetching errors from the ContentFetcherService
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                                 .body("Failed to fetch content from URL '" + payload.getUrl() + "': " + e.getMessage());
        }
    }
}